final:
module top_module(A, B, C, D, desel, Y);input A, B, C, D;
input [1:0] desel;
output reg Y;

always @ (desel or A or B or C or D)
begin

	if (desel == 0)
		Y <= A;
	else
	begin
		if (desel == 1)
			Y <= B;
		else
		begin
			if (desel == 2)
				Y <= C;
			else
			begin
				if (desel == 3)
					Y <= D;
				else
					Y <= 1'bx;
			end
		end
	end
end

endmodule
